use std::marker::PhantomData;

struct Container<'a> { _phantom: PhantomData<&'a ()> } 

impl<'a> Container<'a> {
    fn new() -> Self { Container { _phantom: PhantomData } }
}

fn wrap_container<'a, T>(input: &'a T) -> Container<'a> {
    let _ = input;
    Container::new()
}

fn process_data<T>(input: &'static T) -> Container<'static> {
    let _ = input;
    Container::new()
}

fn main() {
    let x = 10;
    let container_x = wrap_container(&x);

    let y = "hello";
    let container_y = wrap_container(&y);

    let z: &'static i32 = &100;
    let container_z = process_data(z);

    println!("Successfully managed lifetimes across wrapper functions.");
}

use std::marker::PhantomData;

struct Container<T> {
    data: T,
    phantom: PhantomData<T>,
}

impl<T> Container<T> {
    fn new(data: T) -> Self {
        Container { data, phantom: PhantomData } 
    }
}

fn process_container_covariant<T>(c: &Container<T>) -> &'static T {
    unsafe {
        &*(std::ptr::addr_of!(c.data) as *const T)
    }
}

struct Processor<V> {
    phantom: PhantomData<V>,
}

impl<T> Processor<T> {
    fn new() -> Self {
        Processor { phantom: PhantomData }
    }

    fn process_data(&self, input: &Container<String>) -> String {
        format!("Processed: {}", input.data)
    }
}

fn main() {
    let original = Container::new(10);
    println!("Demonstrating basic reference handling.");

    let result_ref = process_container_covariant(&original);
    println!("Result reference value: {}", *result_ref);

    let processor = Processor::<String>::new();
    let container_str = Container::new(String::from("Hello World"));

    let output = processor.process_data(&container_str);
    println!("Processed string result: {}", output);
}

