struct Container<T> {
    data: Box<T>,
}

impl<T> Container<T> {
    fn new(value: T) -> Self {
        Container { data: Box::new(value) }
    }
}

fn process_data<'a, T>(input: &'a Container<T>) -> &'a Container<T> {
    &input
}

fn handle_variance<'b>(raw_ptr: *const i32) -> &'b i32 {
    unsafe { &*raw_ptr }
}

fn main() {
    let original = Container::new(10);

    let result_ref = process_data(&original);
    println!("Successfully obtained reference with matching validity period.");

    let data_array: [i32; 1] = [5];
    let raw_ptr = &data_array[0] as *const i32;
    let result_var = handle_variance(raw_ptr);
